// Get campaign config from webhook trigger
const config = $('Webhook Trigger1').first().json.body
const batchSize = config.batchSize || 50;
const messages = $input.all();


console.log("Splitting messages into Batches...")
// Split messages into batches
const batches = [];
for (let i = 0; i < messages.length; i += batchSize) {
  batches.push({
    batchIndex: Math.floor(i / batchSize),
    messages: messages.slice(i, i + batchSize).map(m => m.json),
    totalBatches: Math.ceil(messages.length / batchSize),
    totalMessages: messages.length,
    campaignId: config.campaignId,
    instanceName: config.instanceName || 'whatsapp-main',
    messageDelay: config.messageDelay || 2,
    batchDelay: config.batchDelay || 30,
    autoRetry: config.autoRetry || false,
    maxRetries: config.maxRetries || 3
  });
}

// If no messages, return empty batch to handle completion
if (batches.length === 0) {
  return [{
    json: {
      batchIndex: 0,
      messages: [],
      totalBatches: 0,
      totalMessages: 0,
      campaignId: config.campaignId,
      instanceName: config.instanceName || 'whatsapp-main',
      messageDelay: config.messageDelay || 2,
      batchDelay: config.batchDelay || 30,
      noMessages: true
    }
  }];
}

return batches.map(batch => ({ json: batch }));

// Extract messages from current batch
const batch = $('Loop Batches1').item.json;
const messages = batch.messages || [];

// Return each message as separate item for processing
return messages.map(msg => ({
  json: {
    ...msg,
    campaignId: batch.campaignId,
    instanceName: batch.instanceName,
    messageDelay: batch.messageDelay,
    batchIndex: batch.batchIndex,
    totalBatches: batch.totalBatches
  }
}));

// Campaign was paused or cancelled during execution
const campaignId = $('Webhook Trigger1').first().json.body.campaignId;
const currentStatus = $('Check Status In Loop1').first().json.status;

console.log(`Campaign ${campaignId} is now ${currentStatus}, stopping execution`);

return [{
  json: {
    campaignId,
    status: currentStatus,
    message: `Campaign execution stopped - status changed to ${currentStatus}`
  }
}];

